class Solution:
    def paintWalls(self, cost: List[int], time: List[int]) -> int:
        n = len(cost)
        dp = [float('inf')] * (n + 1)
        dp[0] = 0

        for i in range(n):
            for j in range(n, i - 1, -1):
                dp[j] = min(dp[j], dp[j - 1] + cost[i])
                if j - 1 >= 0:
                    dp[j] = min(dp[j], dp[j - 1] + cost[i])
                if j - time[i] - 1 >= 0:
                    dp[j] = min(dp[j], dp[j - time[i] - 1] + cost[i])

        return dp[n]
